-    emitRemarkWithHints();
-    return false;
-  }
-
-  if (VectorizeOnlyWhenForced && getForce() != LoopVectorizeHints::FK_Enabled) {
-    LLVM_DEBUG(dbgs() << "LV: Not vectorizing: No #pragma vectorize enable.\n");
-    emitRemarkWithHints();
-    return false;
-  }
-
-  if (getIsVectorized() == 1) {
