-bool LoopVectorizeHints::Hint::validate(unsigned Val) {
-  switch (Kind) {
-  case HK_WIDTH:
-    return isPowerOf2_32(Val) && Val <= VectorizerParams::MaxVectorWidth;
-  case HK_INTERLEAVE:
-    return isPowerOf2_32(Val) && Val <= MaxInterleaveFactor;
-  case HK_FORCE:
-    return (Val <= 1);
-  case HK_ISVECTORIZED:
-  case HK_PREDICATE:
-  case HK_SCALABLE:
-    return (Val == 0 || Val == 1);
-  }
-  return false;
-}
